-- AI Car Concierge — Vehicle Inventory
-- 100 vehicles: mix of years 2019-2025 (pre-2022 are "Pending De-listing")

CREATE TABLE IF NOT EXISTS inventory (
    id INTEGER PRIMARY KEY AUTOINCREMENT,
    make TEXT NOT NULL,
    model TEXT NOT NULL,
    year INTEGER NOT NULL,
    trim TEXT,
    color TEXT,
    fuel_type TEXT NOT NULL,  -- 'Electric', 'Gasoline', 'Hybrid'
    transmission TEXT,        -- 'Automatic', 'Manual'
    mileage INTEGER DEFAULT 0,
    price REAL NOT NULL,
    stock_count INTEGER NOT NULL DEFAULT 1,
    vin TEXT UNIQUE,
    description TEXT
);

